from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Get the main subject (most triples)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s]))
    main_triples = subject_triples[main_subject]

    # Categorize predicates for better sentence construction
    location_predicates = ['country', 'city', 'regionServed', 'location', 'foundationPlace']
    financial_predicates = ['netIncome', 'operatingIncome', 'revenue', 'cost', 'numberOfEmployees', 'numberOfLocations']
    personnel_predicates = ['leader', 'keyPerson', 'leaderParty']
    company_predicates = ['industry', 'type', 'service', 'product', 'subsidiary', 'parentCompany']
    geographic_predicates = ['areaTotal', 'populationDensity', 'populationTotal', 'elevationAboveTheSeaLevel']

    # Build sentence parts
    parts = []
    remaining_triples = []

    # Find country/location first for context
    for triple in main_triples:
        if triple.predicate == 'country':
            parts.append(f"{main_subject} is located in {triple.object}")
            break

    # Add other information
    for triple in main_triples:
        if triple.predicate == 'country':
            continue
        elif triple.predicate == 'foundingDate':
            parts.append(f"established in {triple.object}")
        elif triple.predicate == 'industry':
            parts.append(f"operates in the {triple.object}")
        elif triple.predicate == 'city':
            parts.append(f"based in {triple.object}")
        elif triple.predicate == 'type':
            parts.append(f"a {triple.object}")
        elif triple.predicate == 'service':
            parts.append(f"provides {triple.object}")
        elif triple.predicate in financial_predicates:
            if 'Income' in triple.predicate or 'revenue' in triple.predicate:
                parts.append(f"with {triple.predicate.replace('Income', '').lower()} of {triple.object}")
            else:
                parts.append(f"with {triple.predicate.replace(' ', '')} of {triple.object}")
        elif triple.predicate in personnel_predicates:
            parts.append(f"led by {triple.object}")
        elif triple.predicate in company_predicates:
            if triple.predicate == 'parentCompany':
                parts.append(f"a subsidiary of {triple.object}")
            elif triple.predicate == 'subsidiary':
                parts.append(f"owns {triple.object}")
            else:
                parts.append(f"specializing in {triple.object}")
        elif triple.predicate in geographic_predicates:
            parts.append(f"covering an area with {triple.predicate.replace('Total', '').lower()} of {triple.object}")
        elif triple.predicate == 'capital':
            parts.append(f"the capital is {triple.object}")
        elif triple.predicate == 'language':
            parts.append(f"with {triple.object} as the official language")
        elif triple.predicate == 'leaderTitle':
            parts.append(f"where the leader holds the title of {triple.object}")
        elif triple.predicate == 'alternativeName':
            parts.append(f"also known as {triple.object}")
        elif triple.predicate == 'birthDate':
            parts.append(f"born on {triple.object}")
        elif triple.predicate == 'isPartOf':
            parts.append(f"part of {triple.object}")
        elif triple.predicate == 'longName':
            parts.append(f"officially known as {triple.object}")
        elif triple.predicate == 'motto':
            parts.append(f"with the motto \"{triple.object}\"")
        else:
            parts.append(f"whose {triple.predicate} is {triple.object}")

    # Combine parts into a coherent sentence
    if len(parts) == 0:
        return f"{main_subject} is a company."
    elif len(parts) == 1:
        return f"{main_subject} is {parts[0]}."
    elif len(parts) == 2:
        return f"{main_subject} is {parts[0]}, {parts[1]}."
    else:
        # Build complex sentence with proper conjunctions
        result = f"{main_subject}"
        if parts[0].startswith(f"{main_subject}"):
            result = parts[0]
        else:
            result = f"{main_subject} is {parts[0]}"

        for i, part in enumerate(parts[1:], 1):
            if i == 1:
                result += f", {part}"
            else:
                result += f", and {part}"

        result += "."
        return result

# EVOLVE-BLOCK-END
